// Get Filter output (instead of Webhook1)
const data =$input.first().json.body.entry[0].messaging[0];

// Extract values
const senderId = data.sender.id;
const messageText = data.message.text;

// Format timestamp
const timestamp = $input.first().json.body.entry[0].time;

const formattedTime = new Date(timestamp).toLocaleString('en-PH', {
  month: 'long',
  day: 'numeric',
  year: 'numeric',
  hour: 'numeric',
  minute: '2-digit',
  second: '2-digit',
  hour12: true,
  timeZone: 'Asia/Manila'
});


// Return output
return [
  {
    json: {
      senderId,
      messageText,
      formattedTime,
    }
  }
];

// Get incoming item
const item = $json;

// List of fields to check
const fieldsToCheck = [
  "Sender Id",
  "First Name",
  "Middle Name",
  "Last Name",
  "Suffix",
  "Contact No.",
  "Email",
  "Email Status",
  "Address",
  "Discovery Meeting Id",
  "Discovery Meeting Link",
  "Meeting Time And Date",
  "Client Status"
];

let output = {};
let exists = false;

// Loop through fields
for (const field of fieldsToCheck) {
  const val = item[field];

  // If field has real data, mark exists
  if (val !== undefined && val !== null && String(val).trim() !== "") {
    exists = true;
    output[field] = val;             // return value
  } else {
    output[field] = "No Record";     // return No Record
  }
}

// Add sender status
output.Sender_Status = exists ? "Recurring Sender" : "New Sender";

// n8n requires array output
return [
  {
    json: output
  }
];

// Get the incoming data
const item = $json;

// The fields we want to check
const fieldsToCheck = [
  "Sender Id",
  "Time Stamp",
  "Chat History",
  "Summary",
  "MID"
];

let output = {};

// Loop and set values or "No Record"
for (const field of fieldsToCheck) {
  const val = item[field];

  if (val !== undefined && val !== null && String(val).trim() !== "") {
    output[field] = val;             // actual value
  } else {
    output[field] = "No Record";     // missing or empty
  }
}

// Return in the required format for n8n
return [
  {
    json: output
  }
];

// Get the incoming text (the field that is causing "JSON parameter needs to be valid JSON")
const text = $json.output || "";

// Correct variable name
const Sender_Id = $('Sender Status').first().json["Sender Id"];

// Safely convert to valid JSON by wrapping it in an object
// and escaping all illegal characters automatically
return [
  {
    json: {
      Sender_Id,
      cleaned_output: text
        .replace(/\r?\n|\r/g, " ")     // remove line breaks
        .replace(/"/g, '\\"')          // escape double quotes
        .trim()
    }
  }
];

